cd "$(cat /tmp/wsdir | cut -d= -f2)"; for q in 131819 412823 55315 661416 915784; do echo "=== $q ==="; grep -A 3 "^### $q " memory/q_detail.txt | head -4; for f in $(ls -t predictions/*.json); do python3 -c "
import json
d=json.load(open('$f'))
for e in d:
    if e['question_id']=='$q': print('  PRED:', e['outcomes'])
" 2>/dev/null; done | head -1; done
